"""Voronoi-based circle packing using Lloyd's algorithm for centroidal optimization."""
import numpy as np
from scipy.spatial import Voronoi

def construct_packing():
    """Lloyd's algorithm: iteratively move centers to Voronoi cell centroids."""
    n = 26
    centers = _init_hex(n)
    best_sum, best_c = 0, centers.copy()
    np.random.seed(42)

    for trial in range(12):
        c = best_c + (np.random.randn(n, 2) * 0.04 if trial > 0 else 0)
        c = np.clip(c, 0.05, 0.95)

        for _ in range(200):
            m = _mirrors(c)
            vor = Voronoi(np.vstack([c, m]))
            new_c = np.zeros_like(c)
            for i in range(n):
                cell = _cell(vor, i)
                cell = _clip(cell)
                new_c[i] = _centroid(cell) if len(cell) >= 3 else c[i]
            if np.max(np.linalg.norm(new_c - c, axis=1)) < 1e-9:
                break
            c = new_c

        r = _radii(c)
        if np.sum(r) > best_sum:
            best_sum, best_c = np.sum(r), c.copy()

    return best_c, _radii(best_c), best_sum

def _init_hex(n):
    c = np.zeros((n, 2))
    dx, dy = 0.19, 0.19 * np.sqrt(3) / 2
    rows = [(4, 0), (5, dy), (6, 2*dy), (6, 3*dy), (5, 4*dy)]
    idx = 0
    for cnt, y in rows:
        x0 = 0.5 - (cnt-1)*dx/2
        for j in range(cnt):
            c[idx] = [x0 + j*dx, 0.10 + y]
            idx += 1
    return c

def _mirrors(c):
    m = []
    for p in c:
        m.extend([[-p[0], p[1]], [2-p[0], p[1]], [p[0], -p[1]], [p[0], 2-p[1]]])
    return np.array(m)

def _cell(vor, i):
    r = vor.regions[vor.point_region[i]]
    if -1 in r or len(r) < 3:
        return np.array([[0.1, 0.1], [0.9, 0.1], [0.9, 0.9], [0.1, 0.9]])
    return np.array([vor.vertices[j] for j in r])

def _clip(poly):
    def clip_hp(poly, test):
        new = []
        for i in range(len(poly)):
            p1, p2 = poly[i], poly[(i+1) % len(poly)]
            in1, in2 = test(p1), test(p2)
            if in1: new.append(p1)
            if in1 != in2:
                lo, hi = 0.0, 1.0
                for _ in range(15):
                    mid = (lo + hi) / 2
                    pm = p1 + mid * (p2 - p1)
                    if test(pm): lo = mid
                    else: hi = mid
                new.append(p1 + lo * (p2 - p1))
        return np.array(new) if new else np.array([])

    poly = np.array(poly)
    if len(poly) < 3: return poly
    poly = clip_hp(poly, lambda p: p[0] >= 0)
    if len(poly) < 3: return poly
    poly = clip_hp(poly, lambda p: p[0] <= 1)
    if len(poly) < 3: return poly
    poly = clip_hp(poly, lambda p: p[1] >= 0)
    if len(poly) < 3: return poly
    poly = clip_hp(poly, lambda p: p[1] <= 1)
    return poly

def _centroid(poly):
    if len(poly) < 3: return np.mean(poly, axis=0) if len(poly) > 0 else np.array([0.5, 0.5])
    n = len(poly)
    a = sum(poly[i,0]*poly[(i+1)%n,1] - poly[(i+1)%n,0]*poly[i,1] for i in range(n))
    if abs(a) < 1e-10: return np.mean(poly, axis=0)
    cx = sum((poly[i,0]+poly[(i+1)%n,0])*(poly[i,0]*poly[(i+1)%n,1]-poly[(i+1)%n,0]*poly[i,1]) for i in range(n)) / (6*a)
    cy = sum((poly[i,1]+poly[(i+1)%n,1])*(poly[i,0]*poly[(i+1)%n,1]-poly[(i+1)%n,0]*poly[i,1]) for i in range(n)) / (6*a)
    return np.array([cx, cy])

def _radii(c):
    n = len(c)
    r = np.zeros(n)
    for i in range(n):
        r[i] = min(c[i,0], c[i,1], 1-c[i,0], 1-c[i,1])
        for j in range(n):
            if i != j: r[i] = min(r[i], np.linalg.norm(c[i]-c[j])/2)
        r[i] = max(0.001, r[i])
    return r
